69	function processClaim(
70	  step: any,
71	  policies: Record<number, any[]>,
72	  capRemaining: Record<number, number>,
73	): { payout: number; remainingCap: number } {
74	  const policyItems = policies[step.policy];
75	  const insuranceSum = policyItems.reduce(
76	    (sum: number, item: any) => sum + (INSURANCE_VALUE[item.type] ?? 0),
77	    0,
78	  );
79	  if (!(step.policy in capRemaining)) {
80	    capRemaining[step.policy] = insuranceSum * 2;
81	  }
82	  let totalPayout = 0;
83	  for (const damage of step.incident.damages) {
84	    const payout = damage.amount - DEDUCTIBLE;
85	    totalPayout += Math.max(0, payout);
86	  }
87	  totalPayout = Math.min(totalPayout, capRemaining[step.policy]);
88	  totalPayout = Math.floor(totalPayout);
89	  capRemaining[step.policy] -= totalPayout;
90	  return { payout: totalPayout, remainingCap: capRemaining[step.policy] };
91	}
