93	function processQuote(
94	  step: any,
95	  index: number,
96	  yearsWithMHPCO: number,
97	): { premium: number } {
98	  const { itemPremiums, policyBase } = computePremiumBreakdown(step.items);
99	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
100	  const loyaltyDiscount =
101	    yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
102	      ? policyBase * LOYALTY_DISCOUNT_RATE
103	      : 0;
104	  const followUpDiscount =
105	    index > 0 ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
106	  const premium =
107	    Math.ceil(
108	      itemPremiums +
109	        firstInsuranceSurcharge -
110	        loyaltyDiscount -
111	        followUpDiscount,
112	    ) + PROCESSING_FEE;
113	  return { premium };
114	}
