116	export function processScenario(scenario: any): unknown {
117	  const policies: Record<number, any[]> = {};
118	  const capRemaining: Record<number, number> = {};
119	
120	  const results = scenario.steps.map((step: any, index: number) => {
121	    if (step.op === "claim") {
122	      return processClaim(step, policies, capRemaining);
123	    }
124	    policies[index] = step.items;
125	    return processQuote(step, index, scenario.customer.yearsWithMHPCO);
126	  });
127	  return { results };
128	}
